922 void SampleProfileMatcher::runOnModule() {
923   ProfileConverter::flattenProfile(Reader.getProfiles(), FlattenedProfiles,
924                                    FunctionSamples::ProfileIsCS);
925   if (SalvageUnusedProfile)
926     findFunctionsWithoutProfile();
927 
928   // Process the matching in top-down order so that the caller matching result
929   // can be used to the callee matching.
930   std::vector<Function *> TopDownFunctionList;
931   TopDownFunctionList.reserve(M.size());
932   buildTopDownFuncOrder(CG, TopDownFunctionList);
933   for (auto *F : TopDownFunctionList) {
934     if (skipProfileForFunction(*F))
935       continue;
936     runOnFunction(*F);
937   }
938 
939   if (SalvageUnusedProfile)
940     UpdateWithSalvagedProfiles();
941 
942   if (SalvageStaleProfile)
943     distributeIRToProfileLocationMap();
944 
945   computeAndReportProfileStaleness();
946 }
