134 void SampleProfileMatcher::findProfileAnchors(
135     const FunctionSamples &FS, AnchorMap &ProfileAnchors,
136     AnchorTargetMap &ProfileAnchorTargets) const {
137   auto isInvalidLineOffset = [](uint32_t LineOffset) {
138     return LineOffset & 0x8000;
139   };
140 
141   auto InsertAnchor = [](const LineLocation &Loc, const FunctionId &CalleeName,
142                          AnchorMap &ProfileAnchors,
143                          AnchorTargetMap &ProfileAnchorTargets) {
144     auto Ret = ProfileAnchors.try_emplace(Loc, CalleeName);
145     if (!Ret.second) {
146       if (Ret.first->second != FunctionId(UnknownIndirectCallee)) {
147         // First conflict: save the previously inserted target.
148         ProfileAnchorTargets[Loc].push_back(Ret.first->second);
149       }
150       // Save the new conflicting target.
151       if (CalleeName != FunctionId(UnknownIndirectCallee))
152         ProfileAnchorTargets[Loc].push_back(CalleeName);
153       // For multiple callees, which indicates it's an indirect call, we use a
154       // dummy name(UnknownIndirectCallee) as the indrect callee name.
155       Ret.first->second = FunctionId(UnknownIndirectCallee);
156     }
157   };
158 
159   for (const auto &I : FS.getBodySamples()) {
160     const LineLocation &Loc = I.first;
161     if (isInvalidLineOffset(Loc.LineOffset))
162       continue;
163     for (const auto &C : I.second.getCallTargets())
164       InsertAnchor(Loc, C.first, ProfileAnchors, ProfileAnchorTargets);
165   }
166 
167   for (const auto &I : FS.getCallsiteSamples()) {
168     const LineLocation &Loc = I.first;
169     if (isInvalidLineOffset(Loc.LineOffset))
170       continue;
171     for (const auto &C : I.second)
172       InsertAnchor(Loc, C.first, ProfileAnchors, ProfileAnchorTargets);
173   }
174 }
