210 LocToLocMap SampleProfileMatcher::longestCommonSequence(
211     const AnchorList &AnchorList1, const AnchorList &AnchorList2,
212     const AnchorTargetMap &ProfileAnchorTargets, bool MatchUnusedFunction) {
213   LocToLocMap MatchedAnchors;
214   llvm::longestCommonSequence<LineLocation, FunctionId>(
215       AnchorList1, AnchorList2,
216       [&](const std::pair<LineLocation, FunctionId> &A,
217           const std::pair<LineLocation, FunctionId> &B) {
218         if (functionMatchesProfile(
219                 A.second, B.second,
220                 !MatchUnusedFunction // Find matched function only
221                 ))
222           return true;
223         // When the profile has UnknownIndirectCallee (multiple callees
224         // collapsed), check if the IR callee matches any of the actual call
225         // targets.
226         if (B.second == FunctionId(UnknownIndirectCallee) &&
227             A.second != FunctionId(UnknownIndirectCallee)) {
228           auto TIt = ProfileAnchorTargets.find(B.first);
229           return TIt != ProfileAnchorTargets.end() &&
230                  llvm::is_contained(TIt->second, A.second);
231         }
232         return false;
233       },
234       [&](LineLocation A, LineLocation B) {
235         MatchedAnchors.try_emplace(A, B);
236       });
237   return MatchedAnchors;
238 }
