310 // Call target name anchor based profile fuzzy matching.
311 // Input:
312 // For IR locations, the anchor is the callee name of direct callsite; For
313 // profile locations, it's the call target name for BodySamples or inlinee's
314 // profile name for CallsiteSamples.
315 // Matching heuristic:
316 // First match all the anchors using the diff algorithm, then split the
317 // non-anchor locations between the two anchors evenly, first half are matched
318 // based on the start anchor, second half are matched based on the end anchor.
319 // For example, given:
320 // IR locations:      [1, 2(foo), 3, 5, 6(bar), 7]
321 // Profile locations: [1, 2, 3(foo), 4, 7, 8(bar), 9]
322 // The matching gives:
323 //   [1,    2(foo), 3,  5,  6(bar), 7]
324 //    |     |       |   |     |     |
325 //   [1, 2, 3(foo), 4,  7,  8(bar), 9]
326 // The output mapping: [2->3, 3->4, 5->7, 6->8, 7->9].
327 void SampleProfileMatcher::runStaleProfileMatching(
328     const Function &F, const AnchorMap &IRAnchors,
329     const AnchorMap &ProfileAnchors,
330     const AnchorTargetMap &ProfileAnchorTargets,
331     LocToLocMap &IRToProfileLocationMap, bool RunCFGMatching,
332     bool RunCGMatching) {
333   if (!RunCFGMatching && !RunCGMatching)
334     return;
335   LLVM_DEBUG(dbgs() << "Run stale profile matching for " << F.getName()
336                     << "\n");
337   assert(IRToProfileLocationMap.empty() &&
338          "Run stale profile matching only once per function");
339 
340   AnchorList FilteredProfileAnchorList;
341   AnchorList FilteredIRAnchorsList;
342   getFilteredAnchorList(IRAnchors, ProfileAnchors, FilteredIRAnchorsList,
343                         FilteredProfileAnchorList);
344 
345   if (FilteredIRAnchorsList.empty() || FilteredProfileAnchorList.empty())
346     return;
347 
348   if (FilteredIRAnchorsList.size() > SalvageStaleProfileMaxCallsites ||
349       FilteredProfileAnchorList.size() > SalvageStaleProfileMaxCallsites) {
350     LLVM_DEBUG(dbgs() << "Skip stale profile matching for " << F.getName()
351                       << " because the number of callsites in the IR is "
352                       << FilteredIRAnchorsList.size()
353                       << " and in the profile is "
354                       << FilteredProfileAnchorList.size() << "\n");
355     return;
356   }
357 
358   // Match the callsite anchors by finding the longest common subsequence
359   // between IR and profile.
360   // Define a match between two anchors as follows:
361   // 1) The function names of anchors are the same.
362   // 2) The similarity between the anchor functions is above a threshold if
363   // RunCGMatching is set.
364   // For 2), we only consider the anchor functions from IR and profile don't
365   // appear on either side to reduce the matching scope. Note that we need to
366   // use IR anchor as base(A side) to align with the order of
367   // IRToProfileLocationMap.
368   LocToLocMap MatchedAnchors = longestCommonSequence(
369       FilteredIRAnchorsList, FilteredProfileAnchorList, ProfileAnchorTargets,
370       RunCGMatching /* Match unused functions */);
371 
372   // CFG level matching:
373   // Apply the callsite matchings to infer matching for the basic
374   // block(non-callsite) locations and write the result to
375   // IRToProfileLocationMap.
376   if (RunCFGMatching)
377     matchNonCallsiteLocs(MatchedAnchors, IRAnchors, IRToProfileLocationMap);
378 }
