380 void SampleProfileMatcher::runOnFunction(Function &F) {
381   // We need to use flattened function samples for matching.
382   // Unlike IR, which includes all callsites from the source code, the callsites
383   // in profile only show up when they are hit by samples, i,e. the profile
384   // callsites in one context may differ from those in another context. To get
385   // the maximum number of callsites, we merge the function profiles from all
386   // contexts, aka, the flattened profile to find profile anchors.
387   const auto *FSForMatching = getFlattenedSamplesFor(F);
388   if (SalvageUnusedProfile && !FSForMatching) {
389     // Apply the matching in place to find the new function's matched profile.
390     auto R = FuncToProfileNameMap.find(&F);
391     if (R != FuncToProfileNameMap.end()) {
392       FSForMatching = getFlattenedSamplesFor(R->second);
393       // Try to find the salvaged top-level profiles that are explicitly loaded
394       // for the matching, see "functionMatchesProfileHelper" for the details.
395       if (!FSForMatching && LoadFuncProfileforCGMatching)
396         FSForMatching = Reader.getSamplesFor(R->second.stringRef());
397     }
398   }
399   if (!FSForMatching)
400     return;
401 
402   // Anchors for IR. It's a map from IR location to callee name, callee name is
403   // empty for non-call instruction and use a dummy name(UnknownIndirectCallee)
404   // for unknown indrect callee name.
405   AnchorMap IRAnchors;
406   findIRAnchors(F, IRAnchors);
407   // Anchors for profile. It's a map from callsite location to a set of callee
408   // name.
409   AnchorMap ProfileAnchors;
410   AnchorTargetMap ProfileAnchorTargets;
411   findProfileAnchors(*FSForMatching, ProfileAnchors, ProfileAnchorTargets);
412 
413   // Compute the callsite match states for profile staleness report.
414   if (ReportProfileStaleness || PersistProfileStaleness)
415     recordCallsiteMatchStates(F, IRAnchors, ProfileAnchors,
416                               ProfileAnchorTargets, nullptr);
417 
418   if (!SalvageStaleProfile)
419     return;
420   // For probe-based profiles, run matching only when profile checksum is
421   // mismatched.
422   bool ChecksumMismatch = FunctionSamples::ProfileIsProbeBased &&
423                           !ProbeManager->profileIsValid(F, *FSForMatching);
424   bool RunCFGMatching =
425       !FunctionSamples::ProfileIsProbeBased || ChecksumMismatch;
426   bool RunCGMatching = SalvageUnusedProfile;
427   // For imported functions, the checksum metadata(pseudo_probe_desc) are
428   // dropped, so we leverage function attribute(profile-checksum-mismatch) to
429   // transfer the info: add the attribute during pre-link phase and check it
430   // during post-link phase(see "profileIsValid").
431   if (ChecksumMismatch && LTOPhase == ThinOrFullLTOPhase::ThinLTOPreLink)
432     F.addFnAttr("profile-checksum-mismatch");
433 
434   // The matching result will be saved to IRToProfileLocationMap, create a
435   // new map for each function.
436   auto &IRToProfileLocationMap = getIRToProfileLocationMap(F);
437   runStaleProfileMatching(F, IRAnchors, ProfileAnchors, ProfileAnchorTargets,
438                           IRToProfileLocationMap, RunCFGMatching,
439                           RunCGMatching);
440   // Find and update callsite match states after matching.
441   if (RunCFGMatching && (ReportProfileStaleness || PersistProfileStaleness))
442     recordCallsiteMatchStates(F, IRAnchors, ProfileAnchors,
443                               ProfileAnchorTargets, &IRToProfileLocationMap);
444 }
