446 void SampleProfileMatcher::recordCallsiteMatchStates(
447     const Function &F, const AnchorMap &IRAnchors,
448     const AnchorMap &ProfileAnchors,
449     const AnchorTargetMap &ProfileAnchorTargets,
450     const LocToLocMap *IRToProfileLocationMap) {
451   bool IsPostMatch = IRToProfileLocationMap != nullptr;
452   auto &CallsiteMatchStates =
453       FuncCallsiteMatchStates[FunctionSamples::getCanonicalFnName(F.getName())];
454 
455   auto MapIRLocToProfileLoc = [&](const LineLocation &IRLoc) {
456     // IRToProfileLocationMap is null in pre-match phrase.
457     if (!IRToProfileLocationMap)
458       return IRLoc;
459     const auto &ProfileLoc = IRToProfileLocationMap->find(IRLoc);
460     if (ProfileLoc != IRToProfileLocationMap->end())
461       return ProfileLoc->second;
462     else
463       return IRLoc;
464   };
465 
466   for (const auto &I : IRAnchors) {
467     // After fuzzy profile matching, use the matching result to remap the
468     // current IR callsite.
469     const auto &ProfileLoc = MapIRLocToProfileLoc(I.first);
470     const auto &IRCalleeId = I.second;
471     const auto &It = ProfileAnchors.find(ProfileLoc);
472     if (It == ProfileAnchors.end())
473       continue;
474     const auto &ProfCalleeId = It->second;
475     if (IRCalleeId == ProfCalleeId ||
476         // When the profile has UnknownIndirectCallee (indirect call) but the IR
477         // has a direct call, check if the IR callee matches any of the actual
478         // call targets in the profile.
479         (ProfCalleeId == FunctionId(UnknownIndirectCallee) &&
480          IRCalleeId != FunctionId(UnknownIndirectCallee) && [&]() {
481            auto TIt = ProfileAnchorTargets.find(ProfileLoc);
482            return TIt != ProfileAnchorTargets.end() &&
483                   llvm::is_contained(TIt->second, IRCalleeId);
484          }())) {
485       auto It = CallsiteMatchStates.find(ProfileLoc);
486       if (It == CallsiteMatchStates.end())
487         CallsiteMatchStates.emplace(ProfileLoc, MatchState::InitialMatch);
488       else if (IsPostMatch) {
489         if (It->second == MatchState::InitialMatch)
490           It->second = MatchState::UnchangedMatch;
491         else if (It->second == MatchState::InitialMismatch)
492           It->second = MatchState::RecoveredMismatch;
493       }
494     }
495   }
496 
497   // Check if there are any callsites in the profile that does not match to any
498   // IR callsites.
499   for (const auto &I : ProfileAnchors) {
500     const auto &Loc = I.first;
501     assert(!I.second.stringRef().empty() && "Callees should not be empty");
