516 void SampleProfileMatcher::countMismatchedFuncSamples(const FunctionSamples &FS,
517                                                       bool IsTopLevel) {
518   const auto *FuncDesc = ProbeManager->getDesc(FS.getGUID());
519   // Skip the function that is external or renamed.
520   if (!FuncDesc)
521     return;
522 
523   if (ProbeManager->profileIsHashMismatched(*FuncDesc, FS)) {
524     if (IsTopLevel)
