527     // checksum is mismatched, it's likely all the callites are mismatched and
528     // dropped. We conservatively count all the samples as mismatched and stop
529     // counting the inlinees' profiles.
530     MismatchedFunctionSamples += FS.getTotalSamples();
531     return;
532   }
533 
534   // Even the current-level function checksum is matched, it's possible that the
535   // nested inlinees' checksums are mismatched that affect the inlinee's sample
536   // loading, we need to go deeper to check the inlinees' function samples.
537   // Similarly, count all the samples as mismatched if the inlinee's checksum is
538   // mismatched using this recursive function.
539   for (const auto &I : FS.getCallsiteSamples())
540     for (const auto &CS : I.second)
541       countMismatchedFuncSamples(CS.second, false);
542 }
543 
544 void SampleProfileMatcher::countMismatchedCallsiteSamples(
545     const FunctionSamples &FS) {
546   auto It = FuncCallsiteMatchStates.find(FS.getFuncName());
547   // Skip it if no mismatched callsite or this is an external function.
548   if (It == FuncCallsiteMatchStates.end() || It->second.empty())
549     return;
550   const auto &CallsiteMatchStates = It->second;
551 
552   auto findMatchState = [&](const LineLocation &Loc) {
553     auto It = CallsiteMatchStates.find(Loc);
554     if (It == CallsiteMatchStates.end())
555       return MatchState::Unknown;
556     return It->second;
557   };
558 
559   auto AttributeMismatchedSamples = [&](const enum MatchState &State,
560                                         uint64_t Samples) {
561     if (isMismatchState(State))
562       MismatchedCallsiteSamples += Samples;
563     else if (State == MatchState::RecoveredMismatch)
564       RecoveredCallsiteSamples += Samples;
565   };
566 
567   // The non-inlined callsites are saved in the body samples of function
568   // profile, go through it to count the non-inlined callsite samples.
569   for (const auto &I : FS.getBodySamples())
570     AttributeMismatchedSamples(findMatchState(I.first), I.second.getSamples());
571 
572   // Count the inlined callsite samples.
573   for (const auto &I : FS.getCallsiteSamples()) {
574     auto State = findMatchState(I.first);
575     uint64_t CallsiteSamples = 0;
576     for (const auto &CS : I.second)
577       CallsiteSamples += CS.second.getTotalSamples();
578     AttributeMismatchedSamples(State, CallsiteSamples);
579 
580     if (isMismatchState(State))
581       continue;
582 
583     // When the current level of inlined call site matches the profiled call
584     // site, we need to go deeper along the inline tree to count mismatches from
585     // lower level inlinees.
586     for (const auto &CS : I.second)
587       countMismatchedCallsiteSamples(CS.second);
588   }
589 }
590 
591 void SampleProfileMatcher::countMismatchCallsites(const FunctionSamples &FS) {
592   auto It = FuncCallsiteMatchStates.find(FS.getFuncName());
593   // Skip it if no mismatched callsite or this is an external function.
594   if (It == FuncCallsiteMatchStates.end() || It->second.empty())
595     return;
596   const auto &MatchStates = It->second;
597   [[maybe_unused]] bool OnInitialState =
598       isInitialState(MatchStates.begin()->second);
599   for (const auto &I : MatchStates) {
600     TotalProfiledCallsites++;
601     assert(
602         (OnInitialState ? isInitialState(I.second) : isFinalState(I.second)) &&
603         "Profile matching state is inconsistent");
604 
605     if (isMismatchState(I.second))
606       NumMismatchedCallsites++;
607     else if (I.second == MatchState::RecoveredMismatch)
608       NumRecoveredCallsites++;
609   }
610 }
