612 void SampleProfileMatcher::countCallGraphRecoveredSamples(
613     const FunctionSamples &FS,
614     std::unordered_set<FunctionId> &CallGraphRecoveredProfiles) {
615   if (CallGraphRecoveredProfiles.count(FS.getFunction())) {
616     NumCallGraphRecoveredFuncSamples += FS.getTotalSamples();
617     return;
618   }
619 
620   for (const auto &CM : FS.getCallsiteSamples()) {
621     for (const auto &CS : CM.second) {
622       countCallGraphRecoveredSamples(CS.second, CallGraphRecoveredProfiles);
623     }
624   }
625 }
