627 void SampleProfileMatcher::computeAndReportProfileStaleness() {
628   if (!ReportProfileStaleness && !PersistProfileStaleness)
629     return;
630 
631   std::unordered_set<FunctionId> CallGraphRecoveredProfiles;
632   if (SalvageUnusedProfile) {
633     for (const auto &I : FuncToProfileNameMap) {
634       CallGraphRecoveredProfiles.insert(I.second);
635       if (GlobalValue::isAvailableExternallyLinkage(I.first->getLinkage()))
636         continue;
637       NumCallGraphRecoveredProfiledFunc++;
638     }
639   }
640 
641   // Count profile mismatches for profile staleness report.
642   for (const auto &F : M) {
643     if (skipProfileForFunction(F))
644       continue;
645     // As the stats will be merged by linker, skip reporting the metrics for
646     // imported functions to avoid repeated counting.
647     if (GlobalValue::isAvailableExternallyLinkage(F.getLinkage()))
648       continue;
649     const auto *FS = Reader.getSamplesFor(F);
650     if (!FS)
651       continue;
652     TotalProfiledFunc++;
653     TotalFunctionSamples += FS->getTotalSamples();
654 
655     if (SalvageUnusedProfile && !CallGraphRecoveredProfiles.empty())
656       countCallGraphRecoveredSamples(*FS, CallGraphRecoveredProfiles);
657 
658     // Checksum mismatch is only used in pseudo-probe mode.
659     if (FunctionSamples::ProfileIsProbeBased)
660       countMismatchedFuncSamples(*FS, true);
661 
662     // Count mismatches and samples for calliste.
663     countMismatchCallsites(*FS);
664     countMismatchedCallsiteSamples(*FS);
665   }
666 
667   if (ReportProfileStaleness) {
668     if (FunctionSamples::ProfileIsProbeBased) {
669       errs() << "(" << NumStaleProfileFunc << "/" << TotalProfiledFunc
670              << ") of functions' profile are invalid and ("
671              << MismatchedFunctionSamples << "/" << TotalFunctionSamples
672              << ") of samples are discarded due to function hash mismatch.\n";
673     }
674     if (SalvageUnusedProfile) {
675       errs() << "(" << NumCallGraphRecoveredProfiledFunc << "/"
676              << TotalProfiledFunc << ") of functions' profile are matched and ("
677              << NumCallGraphRecoveredFuncSamples << "/" << TotalFunctionSamples
678              << ") of samples are reused by call graph matching.\n";
679     }
680 
681     errs() << "(" << (NumMismatchedCallsites + NumRecoveredCallsites) << "/"
682            << TotalProfiledCallsites
683            << ") of callsites' profile are invalid and ("
684            << (MismatchedCallsiteSamples + RecoveredCallsiteSamples) << "/"
685            << TotalFunctionSamples
686            << ") of samples are discarded due to callsite location mismatch.\n";
687     errs() << "(" << NumRecoveredCallsites << "/"
688            << (NumRecoveredCallsites + NumMismatchedCallsites)
689            << ") of callsites and (" << RecoveredCallsiteSamples << "/"
690            << (RecoveredCallsiteSamples + MismatchedCallsiteSamples)
691            << ") of samples are recovered by stale profile matching.\n";
692   }
693 
694   if (PersistProfileStaleness) {
695     LLVMContext &Ctx = M.getContext();
696     MDBuilder MDB(Ctx);
697 
698     SmallVector<std::pair<StringRef, uint64_t>> ProfStatsVec;
699     if (FunctionSamples::ProfileIsProbeBased) {
700       ProfStatsVec.emplace_back("NumStaleProfileFunc", NumStaleProfileFunc);
701       ProfStatsVec.emplace_back("TotalProfiledFunc", TotalProfiledFunc);
702       ProfStatsVec.emplace_back("MismatchedFunctionSamples",
703                                 MismatchedFunctionSamples);
704       ProfStatsVec.emplace_back("TotalFunctionSamples", TotalFunctionSamples);
705     }
706 
707     if (SalvageUnusedProfile) {
708       ProfStatsVec.emplace_back("NumCallGraphRecoveredProfiledFunc",
709                                 NumCallGraphRecoveredProfiledFunc);
710       ProfStatsVec.emplace_back("NumCallGraphRecoveredFuncSamples",
711                                 NumCallGraphRecoveredFuncSamples);
712     }
713 
714     ProfStatsVec.emplace_back("NumMismatchedCallsites", NumMismatchedCallsites);
715     ProfStatsVec.emplace_back("NumRecoveredCallsites", NumRecoveredCallsites);
716     ProfStatsVec.emplace_back("TotalProfiledCallsites", TotalProfiledCallsites);
717     ProfStatsVec.emplace_back("MismatchedCallsiteSamples",
718                               MismatchedCallsiteSamples);
719     ProfStatsVec.emplace_back("RecoveredCallsiteSamples",
720                               RecoveredCallsiteSamples);
721 
722     auto *MD = MDB.createLLVMStats(ProfStatsVec);
723     auto *NMD = M.getOrInsertNamedMetadata("llvm.stats");
724     NMD->addOperand(MD);
725   }
726 }
