766 bool SampleProfileMatcher::functionMatchesProfileHelper(
767     const Function &IRFunc, const FunctionId &ProfFunc) {
768   // The value is in the range [0, 1]. The bigger the value is, the more similar
769   // two sequences are.
770   float Similarity = 0.0;
771 
772   // Match the functions if they have the same base name(after demangling) and
773   // skip the similarity check.
774   ItaniumPartialDemangler Demangler;
775   // Helper lambda to demangle and get the base name. If the demangling failed,
776   // return an empty string.
777   auto GetBaseName = [&](StringRef FName) {
778     auto FunctionName = FName.str();
779     if (Demangler.partialDemangle(FunctionName.c_str()))
780       return std::string();
781     size_t BaseNameSize = 0;
782     // The demangler API follows the __cxa_demangle one, and thus needs a
783     // pointer that originates from malloc (or nullptr) and the caller is
784     // responsible for free()-ing the buffer.
785     char *BaseNamePtr = Demangler.getFunctionBaseName(nullptr, &BaseNameSize);
786     std::string Result = (BaseNamePtr && BaseNameSize)
787                              ? std::string(BaseNamePtr, BaseNameSize)
788                              : std::string();
789     free(BaseNamePtr);
790     return Result;
791   };
792   auto IRBaseName = GetBaseName(IRFunc.getName());
793   auto ProfBaseName = GetBaseName(ProfFunc.stringRef());
794   if (!IRBaseName.empty() && IRBaseName == ProfBaseName) {
795     LLVM_DEBUG(dbgs() << "The functions " << IRFunc.getName() << "(IR) and "
796                       << ProfFunc << "(Profile) share the same base name: "
797                       << IRBaseName << ".\n");
798     return true;
799   }
800 
801   const auto *FSForMatching = getFlattenedSamplesFor(ProfFunc);
802   // With extbinary profile format, initial profile loading only reads profile
803   // based on current function names in the module.
804   // However, if a function is renamed, sample loader skips to load its original
805   // profile(which has a different name), we will miss this case. To address
806   // this, we load the top-level profile candidate explicitly for the matching.
807   if (!FSForMatching && LoadFuncProfileforCGMatching) {
808     DenseSet<StringRef> TopLevelFunc({ProfFunc.stringRef()});
809     if (std::error_code EC = Reader.read(TopLevelFunc))
810       return false;
811     FSForMatching = Reader.getSamplesFor(ProfFunc.stringRef());
812     LLVM_DEBUG({
813       if (FSForMatching)
814         dbgs() << "Read top-level function " << ProfFunc
815                << " for call-graph matching\n";
816     });
817   }
818   if (!FSForMatching)
819     return false;
820   // The check for similarity or checksum may not be reliable if the function is
821   // tiny, we use the number of basic block as a proxy for the function
822   // complexity and skip the matching if it's too small.
823   if (IRFunc.size() < MinFuncCountForCGMatching ||
824       FSForMatching->getBodySamples().size() < MinFuncCountForCGMatching)
825     return false;
826 
827   // For probe-based function, we first trust the checksum info. If the checksum
828   // doesn't match, we continue checking for similarity.
829   if (FunctionSamples::ProfileIsProbeBased) {
830     const auto *FuncDesc = ProbeManager->getDesc(IRFunc);
831     if (FuncDesc &&
832         !ProbeManager->profileIsHashMismatched(*FuncDesc, *FSForMatching)) {
833       LLVM_DEBUG(dbgs() << "The checksums for " << IRFunc.getName()
834                         << "(IR) and " << ProfFunc << "(Profile) match.\n");
835 
836       return true;
837     }
838   }
839 
840   AnchorMap IRAnchors;
841   findIRAnchors(IRFunc, IRAnchors);
842   AnchorMap ProfileAnchors;
843   AnchorTargetMap ProfileAnchorTargets;
844   findProfileAnchors(*FSForMatching, ProfileAnchors, ProfileAnchorTargets);
845 
846   AnchorList FilteredIRAnchorsList;
847   AnchorList FilteredProfileAnchorList;
848   getFilteredAnchorList(IRAnchors, ProfileAnchors, FilteredIRAnchorsList,
849                         FilteredProfileAnchorList);
850 
851   // Similarly skip the matching if the num of anchors is not enough.
852   if (FilteredIRAnchorsList.size() < MinCallCountForCGMatching ||
853       FilteredProfileAnchorList.size() < MinCallCountForCGMatching)
854     return false;
855 
856   // Use the diff algorithm to find the LCS between IR and profile.
857 
858   // Don't recursively match the callee function to avoid infinite matching,
859   // callee functions will be handled later since it's processed in top-down
860   // order .
861   LocToLocMap MatchedAnchors = longestCommonSequence(
862       FilteredIRAnchorsList, FilteredProfileAnchorList, ProfileAnchorTargets,
863       false /* Match unused functions */);
864 
865   Similarity = static_cast<float>(MatchedAnchors.size()) /
866                FilteredProfileAnchorList.size();
867 
868   LLVM_DEBUG(dbgs() << "The similarity between " << IRFunc.getName()
869                     << "(IR) and " << ProfFunc << "(profile) is "
870                     << format("%.2f", Similarity) << "\n");
871   assert((Similarity >= 0 && Similarity <= 1.0) &&
872          "Similarity value should be in [0, 1]");
873   return Similarity * 100 > FuncProfileSimilarityThreshold;
874 }
