876 // If FindMatchedProfileOnly is set to true, only use the processed function
877 // results. This is used for skipping the repeated recursive matching.
878 bool SampleProfileMatcher::functionMatchesProfile(Function &IRFunc,
879                                                   const FunctionId &ProfFunc,
880                                                   bool FindMatchedProfileOnly) {
881   auto R = FuncProfileMatchCache.find({&IRFunc, ProfFunc});
882   if (R != FuncProfileMatchCache.end())
883     return R->second;
884 
885   if (FindMatchedProfileOnly)
886     return false;
887 
888   bool Matched = functionMatchesProfileHelper(IRFunc, ProfFunc);
889   FuncProfileMatchCache[{&IRFunc, ProfFunc}] = Matched;
890   if (Matched) {
891     FuncToProfileNameMap[&IRFunc] = ProfFunc;
892     LLVM_DEBUG(dbgs() << "Function:" << IRFunc.getName()
893                       << " matches profile:" << ProfFunc << "\n");
894   }
895 
896   return Matched;
897 }
