899 void SampleProfileMatcher::UpdateWithSalvagedProfiles() {
900   DenseSet<StringRef> ProfileSalvagedFuncs;
901   // Update FuncNameToProfNameMap and SymbolMap.
902   for (auto &I : FuncToProfileNameMap) {
903     assert(I.first && "New function is null");
904     FunctionId FuncName(I.first->getName());
905     ProfileSalvagedFuncs.insert(I.second.stringRef());
906     FuncNameToProfNameMap->emplace(FuncName, I.second);
907 
908     // We need to remove the old entry to avoid duplicating the function
909     // processing.
910     SymbolMap->erase(FuncName);
911     SymbolMap->emplace(I.second, I.first);
912   }
913 
914   // With extbinary profile format, initial profile loading only reads profile
915   // based on current function names in the module, so we need to load top-level
916   // profiles for functions with different profile name explicitly after
917   // function-profile name map is established with stale profile matching.
918   Reader.read(ProfileSalvagedFuncs);
919   Reader.setFuncNameToProfNameMap(*FuncNameToProfNameMap);
920 }
